#include <bits/stdc++.h>
using namespace std;
string a,b;
int k,n,m,dp[2003][2003];
int main(){
	cin>>a>>b;
	scanf("%d",&k);
	n=a.size(),m=b.size(),a=" "+a,b=" "+b;
	for(int i=0;i<=n;i++)
		for(int j=0;j<=m;j++){
			if(i==0 && j==0)
				dp[i][j]=0;
			else if(i==0)
				dp[i][j]=dp[i][j-1]+k;
			else if(j==0)
				dp[i][j]=dp[i-1][j]+k;
			else
				dp[i][j]=min(dp[i-1][j-1]+abs(a[i]-b[j]),min(dp[i-1][j],dp[i][j-1])+k);
		}
	printf("%d",dp[n][m]);
	return 0;
}
